APP_NAME = "office_face_recognition_api"
MODEL_DIR = os.environ.get("FACE_API_MODEL_DIR", "./model_store")
DEFAULT_MODEL_PATH = os.path.join(MODEL_DIR, "face_model.pkl")
DEFAULT_LABELS_PATH = os.path.join(MODEL_DIR, "labels.json")
DEFAULT_META_PATH = os.path.join(MODEL_DIR, "meta.json")

os.makedirs(MODEL_DIR, exist_ok=True)


def _now_ts() -> float:
    return time.time()


def _sha256_bytes(b: bytes) -> str:
    return hashlib.sha256(b).hexdigest()


def _softmax(x: np.ndarray) -> np.ndarray:
    x = x.astype(np.float64)
    x = x - np.max(x)
    ex = np.exp(x)
    s = np.sum(ex)
    if s <= 0:
        return np.ones_like(x) / max(1, x.size)
    return ex / s


def _l2_normalize(v: np.ndarray, eps: float = 1e-12) -> np.ndarray:
    n = float(np.linalg.norm(v))
    if n < eps:
        return v
    return v / n


def _read_image_bytes(file_bytes: bytes) -> np.ndarray:
    if Image is None:
        raise HTTPException(status_code=500, detail="PIL not installed. Install pillow.")
    try:
        img = Image.open(io.BytesIO(file_bytes)).convert("RGB")
        return np.array(img)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image data.")


def _ensure_deps():
    if face_recognition is None:
        raise HTTPException(status_code=500, detail="face_recognition not installed.")
    if LogisticRegression is None:
        raise HTTPException(status_code=500, detail="scikit-learn not installed.")


def _extract_face_encodings(
    image_rgb: np.ndarray,
    num_jitters: int = 1,
    model: str = "hog",
    max_faces: int = 0,
) -> Tuple[List[np.ndarray], List[Tuple[int, int, int, int]]]:
    _ensure_deps()
    try:
        locations = face_recognition.face_locations(image_rgb, model=model)
        if max_faces and len(locations) > max_faces:
            locations = locations[:max_faces]
        encs = face_recognition.face_encodings(image_rgb, known_face_locations=locations, num_jitters=num_jitters)
        encs = [np.asarray(e, dtype=np.float32) for e in encs]
        return encs, locations
    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=500, detail="Failed to extract face encodings.")


@dataclass
class FaceModelBundle:
    clf: Any
    classes: List[str]
    class_to_index: Dict[str, int]
    meta: Dict[str, Any]


def _save_bundle(bundle: FaceModelBundle, model_path: str = DEFAULT_MODEL_PATH):
    os.makedirs(os.path.dirname(model_path), exist_ok=True)
    with open(model_path, "wb") as f:
        pickle.dump(bundle, f)


def _load_bundle(model_path: str = DEFAULT_MODEL_PATH) -> FaceModelBundle:
    if not os.path.exists(model_path):
        raise HTTPException(status_code=404, detail="Model not found. Train first.")
    try:
        with open(model_path, "rb") as f:
            bundle = pickle.load(f)
        if not hasattr(bundle, "clf") or not hasattr(bundle, "classes"):
            raise ValueError("Invalid model bundle.")
        return bundle
    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=500, detail="Failed to load model.")


def _scan_training_dir(training_dir: str) -> List[Tuple[str, str]]:
    pairs = []
    if not os.path.isdir(training_dir):
        raise HTTPException(status_code=400, detail="training_dir must be a directory.")
    for root, dirs, files in os.walk(training_dir):
        for fn in files:
            lower = fn.lower()
            if lower.endswith((".jpg", ".jpeg", ".png", ".bmp", ".webp")):
                full = os.path.join(root, fn)
                rel = os.path.relpath(full, training_dir)
                parts = rel.split(os.sep)
                if len(parts) < 2:
                    continue
                label = parts[0]
                pairs.append((label, full))
    return pairs


def _train_from_dir(
    training_dir: str,
    detection_model: str = "hog",
    num_jitters: int = 1,
    max_faces_per_image: int = 1,
    min_images_per_class: int = 1,
    C: float = 10.0,
    max_iter: int = 2000,
) -> FaceModelBundle:
    _ensure_deps()
    pairs = _scan_training_dir(training_dir)
    if not pairs:
        raise HTTPException(status_code=400, detail="No training images found in training_dir.")

    X = []
    y = []
    per_class_counts: Dict[str, int] = {}
    per_class_skipped: Dict[str, int] = {}
    image_hashes: List[str] = []
    used_images: List[Dict[str, Any]] = []

    for label, path in pairs:
        try:
            with open(path, "rb") as f:
                b = f.read()
            image_hashes.append(_sha256_bytes(b))
            img = _read_image_bytes(b)
            encs, locs = _extract_face_encodings(
                img,
                num_jitters=num_jitters,
                model=detection_model,
                max_faces=max_faces_per_image if max_faces_per_image > 0 else 0,
            )
            if not encs:
                per_class_skipped[label] = per_class_skipped.get(label, 0) + 1
                continue
            enc = encs[0]
            X.append(enc)
            y.append(label)
            per_class_counts[label] = per_class_counts.get(label, 0) + 1
            used_images.append({"label": label, "path": path, "sha256": image_hashes[-1], "faces_found": len(encs)})
        except HTTPException:
            raise
        except Exception:
            per_class_skipped[label] = per_class_skipped.get(label, 0) + 1
            continue

    if not X:
        raise HTTPException(status_code=400, detail="No usable faces found in training images.")

    # Filter classes with too few images
    keep_labels = {lbl for lbl, cnt in per_class_counts.items() if cnt >= min_images_per_class}
    if not keep_labels:
        raise HTTPException(status_code=400, detail="No classes meet min_images_per_class requirement.")

    X2 = []
    y2 = []
    for enc, lbl in zip(X, y):
        if lbl in keep_labels:
            X2.append(enc)
            y2.append(lbl)

    X_arr = np.vstack([np.asarray(v, dtype=np.float32) for v in X2])
    y_arr = np.asarray(y2)

    unique_classes = sorted(list(set(y2)))
    if len(unique_classes) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 distinct classes to train.")

    clf = LogisticRegression(
        C=float(C),
        max_iter=int(max_iter),
        multi_class="auto",
        solver="lbfgs",
        n_jobs=None,
    )
    clf.fit(X_arr, y_arr)

    classes = list(clf.classes_)
    class_to_index = {c: i for i, c in enumerate(classes)}

    meta = {
        "app": APP_NAME,
        "trained_at": _now_ts(),
        "training_dir": os.path.abspath(training_dir),
        "detection_model": detection_model,
        "num_jitters": int(num_jitters),
        "max_faces_per_image": int(max_faces_per_image),
        "min_images_per_class": int(min_images_per_class),
        "C": float(C),
        "max_iter": int(max_iter),
        "num_samples": int(X_arr.shape[0]),
        "num_classes": int(len(classes)),
        "per_class_counts": per_class_counts,
        "per_class_skipped": per_class_skipped,
        "used_images_count": len(used_images),
        "used_images_sample": used_images[:50],
    }

    return FaceModelBundle(clf=clf, classes=classes, class_to_index=class_to_index, meta=meta)


def _predict_distribution(
    bundle: FaceModelBundle,
    enc: np.ndarray,
    temperature: float = 1.0,
) -> Dict[str, Any]:
    clf = bundle.clf
    classes = bundle.classes

    enc2 = np.asarray(enc, dtype=np.float32).reshape(1, -1)

    probs = None
    logits = None

    if hasattr(clf, "predict_proba"):
        probs = clf.predict_proba(enc2)[0].astype(np.float64)
        probs = np.clip(probs, 0.0, 1.0)
        s = float(np.sum(probs))
        if s > 0:
            probs = probs / s
    else:
        if hasattr(clf, "decision_function"):
            logits = clf.decision_function(enc2)
            logits = np.asarray(logits, dtype=np.float64).reshape(-1)
            probs = _softmax(logits)
        else:
            raise HTTPException(status_code=500, detail="Model does not support probability outputs.")

    if temperature is None:
        temperature = 1.0
    temperature = float(temperature)
    if temperature <= 0:
        temperature = 1.0

    if temperature != 1.0:
        p = np.asarray(probs, dtype=np.float64)
        p = np.maximum(p, 1e-12)
        p = np.power(p, 1.0 / temperature)
        p = p / np.sum(p)
        probs = p

    dist = {classes[i]: float(probs[i]) for i in range(len(classes))}
    top_idx = int(np.argmax(probs))
    top_label = classes[top_idx]
    top_prob = float(probs[top_idx])

    entropy = float(-np.sum(np.where(probs > 0, probs * np.log(probs), 0.0)))
    return {
        "top_label": top_label,
        "top_probability": top_prob,
        "entropy": entropy,
        "distribution": dist,
    }


class TrainRequest(BaseModel):
    training_dir: str
    detection_model: str = "hog"  # "hog" or "cnn"
    num_jitters: int = 1
    max_faces_per_image: int = 1
    min_images_per_class: int = 1
    C: float = 10.0
    max_iter: int = 2000
    model_path: Optional[str] = None


class PredictResponse(BaseModel):
    model_meta: Dict[str, Any]
    image_sha256: str
    faces_detected: int
    results: List[Dict[str, Any]]


app = FastAPI(title=APP_NAME, version="1.0.0")


@app.get("/health")
def health():
    return {"status": "ok", "time": _now_ts()}


@app.post("/train")
def train(req: TrainRequest):
    model_path = req.model_path or DEFAULT_MODEL_PATH
    bundle = _train_from_dir(
        training_dir=req.training_dir,
        detection_model=req.detection_model,
        num_jitters=req.num_jitters,
        max_faces_per_image=req.max_faces_per_image,
        min_images_per_class=req.min_images_per_class,
        C=req.C,
        max_iter=req.max_iter,
    )
    _save_bundle(bundle, model_path=model_path)

    try:
        with open(DEFAULT_META_PATH, "w", encoding="utf-8") as f:
            json.dump(bundle.meta, f, ensure_ascii=False, indent=2)
        with open(DEFAULT_LABELS_PATH, "w", encoding="utf-8") as f:
            json.dump({"classes": bundle.classes}, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

    return {
        "saved_model_path": os.path.abspath(model_path),
        "meta": bundle.meta,
        "classes": bundle.classes,
    }


@app.post("/predict", response_model=PredictResponse)
async def predict(
    file: UploadFile = File(...),
    model_path: str = Form(DEFAULT_MODEL_PATH),
    detection_model: str = Form("hog"),
    num_jitters: int = Form(1),
    max_faces: int = Form(0),
    temperature: float = Form(1.0),
):
    bundle = _load_bundle(model_path=model_path)

    b = await file.read()
    if not b:
        raise HTTPException(status_code=400, detail="Empty file.")
    image_sha = _sha256_bytes(b)
    img = _read_image_bytes(b)

    encs, locs = _extract_face_encodings(
        img,
        num_jitters=int(num_jitters),
        model=str(detection_model),
        max_faces=int(max_faces) if int(max_faces) > 0 else 0,
    )

    results = []
    for i, enc in enumerate(encs):
        pred = _predict_distribution(bundle, enc, temperature=float(temperature))
        loc = locs[i] if i < len(locs) else None
        results.append(
            {
                "face_index": i,
                "location": {"top": loc[0], "right": loc[1], "bottom": loc[2], "left": loc[3]} if loc else None,
                "top_label": pred["top_label"],
                "top_probability": pred["top_probability"],
                "entropy": pred["entropy"],
                "distribution": pred["distribution"],
            }
        )

    return {
        "model_meta": bundle.meta,
        "image_sha256": image_sha,
        "faces_detected": len(encs),
        "results": results,
    }


@app.get("/model_info")
def model_info(model_path: str = DEFAULT_MODEL_PATH):
    bundle = _load_bundle(model_path=model_path)
    return {"meta": bundle.meta, "classes": bundle.classes}


@app.post("/reload")
def reload_model(model_path: str = DEFAULT_MODEL_PATH):
    bundle = _load_bundle(model_path=model_path)
    return {"loaded_model_path": os.path.abspath(model_path), "meta": bundle.meta, "classes": bundle.classes}


